def coin_game_advantage(coins):
    n = len(coins)
    if n == 0:
        return 0

    from functools import lru_cache

    prefix = [0] * (n + 1)
    for i in range(n):
        prefix[i + 1] = prefix[i] + coins[i]

    @lru_cache(maxsize=None)
    def dp(i):
        if i >= n:
            return 0
        best = float('-inf')
        for take in range(1, 4):
            if i + take <= n:
                gained = prefix[i + take] - prefix[i]
                best = max(best, gained - dp(i + take))
        return best

    return dp(0)

