import unittest

class TestSolution(unittest.TestCase):
    def test_basic_three_coins(self):
        # P1 takes all 3 coins
        self.assertEqual(coin_game_advantage([1, 2, 3]), 6)

    def test_two_coins(self):
        # P1 takes both coins
        self.assertEqual(coin_game_advantage([3, 1]), 4)

    def test_four_coins(self):
        # P1 takes [5,1,1]=7, P2 takes [5]=5, diff=2
        self.assertEqual(coin_game_advantage([5, 1, 1, 5]), 2)

    def test_hidden_empty(self):
        self.assertEqual(coin_game_advantage([]), 0)

    def test_hidden_single(self):
        self.assertEqual(coin_game_advantage([7]), 7)

    def test_hidden_all_ones_six(self):
        # Symmetric: both get 3, diff=0
        self.assertEqual(coin_game_advantage([1, 1, 1, 1, 1, 1]), 0)

    def test_hidden_descending(self):
        # [5, 4, 3, 2, 1]: P1 takes [5,4,3]=12, P2 takes [2,1]=3, diff=9
        self.assertEqual(coin_game_advantage([5, 4, 3, 2, 1]), 9)

    def test_hidden_longer_sequence(self):
        # [2, 7, 3, 4, 1, 8]: optimal diff is 9
        self.assertEqual(coin_game_advantage([2, 7, 3, 4, 1, 8]), 9)

    def test_hidden_range_1_to_10(self):
        # Interesting case where P2 wins by 1
        self.assertEqual(coin_game_advantage(list(range(1, 11))), -1)

    def test_hidden_large_values(self):
        self.assertEqual(coin_game_advantage([1000000]), 1000000)

    def test_hidden_performance(self):
        # 1000 coins, should not timeout
        coins = list(range(1, 1001))
        result = coin_game_advantage(coins)
        self.assertIsInstance(result, int)

if __name__ == '__main__':
    unittest.main()
